&lt;p&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: (33, 37, 41); --darkreader-inline-color: #d1cdc7;&quot;&gt;The correct answer is&amp;nbsp;&lt;/span&gt;&lt;u data-darkreader-inline-color=&quot;&quot; style=&quot;color: (33, 37, 41); --darkreader-inline-color: #d1cdc7;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Tropical Deciduous Forests&lt;/span&gt;&lt;/u&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: (33, 37, 41); --darkreader-inline-color: #d1cdc7;&quot;&gt;.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: (33, 37, 41); --darkreader-inline-color: #d1cdc7;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p data-darkreader-inline-color=&quot;&quot; style=&quot;color: (33, 37, 41); --darkreader-inline-color: #d1cdc7;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;Tropical Deciduous Forests:&lt;/span&gt;&lt;/p&gt;

&lt;ul data-darkreader-inline-color=&quot;&quot; style=&quot;color: (33, 37, 41); --darkreader-inline-color: #d1cdc7;&quot;&gt;
	&lt;li&gt;They are the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;most widespread in India&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;They are also called&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;monsoon forests&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;They&amp;nbsp;spread over regions that&lt;span style=&quot;font-weight: 700;&quot;&gt;&amp;nbsp;receive rainfall&amp;nbsp;between 70-200 cm&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;Based on the&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;availability of water&lt;/span&gt;, these forests are further&amp;nbsp;divided into&amp;nbsp;&lt;span style=&quot;font-weight: 700;&quot;&gt;moist and dry deciduous&lt;/span&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul data-darkreader-inline-color=&quot;&quot; style=&quot;color: (33, 37, 41); --darkreader-inline-color: #d1cdc7;&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Tropical Evergreen Forests&lt;/span&gt;&amp;nbsp;are found in&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;warm and humid areas&amp;nbsp;&lt;/span&gt;with&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;annual precipitation of over 200 cm&lt;/span&gt;&amp;nbsp;and a&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;mean annual temperature above 22&amp;deg;C&lt;/span&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Mountain forests&lt;/span&gt;&amp;nbsp;can be defined as forests
	&lt;ul&gt;
		&lt;li&gt;On land with an&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;elevation of 2500 m above sea&lt;/span&gt;&amp;nbsp;level or higher,&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;irrespective of the slope&lt;/span&gt;, or&lt;/li&gt;
		&lt;li&gt;On land with an&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;elevation of 300&amp;ndash;2500 m&lt;/span&gt;&amp;nbsp;and a&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;slope with sharp changes&lt;/span&gt;&amp;nbsp;in elevation within a short distance.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Mangrove forests&lt;/span&gt;&amp;nbsp;are&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;productive wetlands&lt;/span&gt;&amp;nbsp;that occur in&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;coastal intertidal zones&lt;/span&gt;.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;strong&gt;&lt;u&gt;उष्णकटिबंधीय पर्णपाती वन&lt;/u&gt;&lt;/strong&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;उष्णकटिबंधीय पर्णपाती वन:&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;वे &lt;strong&gt;भारत में सबसे अधिक व्यापक&lt;/strong&gt; हैं।&lt;/li&gt;
	&lt;li&gt;इन्हें &lt;strong&gt;मानसून वन&lt;/strong&gt; भी कहा जाता है।&lt;/li&gt;
	&lt;li&gt;वे उन क्षेत्रों में फैले हुए हैं जहां &lt;strong&gt;70-200 सेमी के बीच वर्षा&lt;/strong&gt; &lt;strong&gt;होती है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;जल की उपलब्धता&lt;/strong&gt; के आधार पर, इन वनों को &lt;strong&gt;आर्द्र&lt;/strong&gt; &lt;strong&gt;और शुष्क पर्णपाती &lt;/strong&gt;में विभाजित किया गया है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;उष्णकटिबंधीय सदाबहार वन गर्म और आर्द्र क्षेत्रों में &lt;/strong&gt;पाए जाते हैं &lt;strong&gt;जहां वार्षिक वर्षा 200 सेमी से अधिक होती है &lt;/strong&gt;और &lt;strong&gt;औसत वार्षिक तापमान 22 डिग्री सेल्सियस से ऊपर होता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;पर्वतीय वनों &lt;/strong&gt;को वनों के रूप में परिभाषित किया जा सकता है:
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;समुद्र &lt;/strong&gt;तल &lt;strong&gt;से 2500 मीटर &lt;/strong&gt;या उससे अधिक &lt;strong&gt;की ऊंचाई &lt;/strong&gt;वाली भूमि पर, &lt;strong&gt;ढलान की परवाह किए बिना&lt;/strong&gt;, या&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;300-2500 मीटर की ऊंचाई &lt;/strong&gt;वाली भूमि पर और थोड़ी दूरी के भीतर ऊंचाई में &lt;strong&gt;तीव्र&lt;/strong&gt; &lt;strong&gt;बदलाव के साथ ढलान।&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: (33, 37, 41); --darkreader-inline-color: #d1cdc7;&quot;&gt;सदाबहार &lt;/span&gt;वन उत्पादक आर्द्रभूमि &lt;/strong&gt;हैं जो &lt;strong&gt;तटीय अंतर्ज्वारीय क्षेत्रों&lt;/strong&gt; में पाए जाते हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Manipur&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color:  (33, 37, 41);&quot;&gt;
	&lt;li&gt;Five Indian states &amp;ndash;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Uttar Pradesh, Uttarakhand, West Bengal, Sikkim, and Bihar&lt;/span&gt;&amp;nbsp;share their borders with Nepal.&lt;/li&gt;
	&lt;li&gt;Manipur does not share its boundary with Nepal.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;2&quot; style=&quot;color:  (33, 37, 41); width: 350px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Country&lt;/span&gt;&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Border Length&lt;/span&gt;&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Bordering States&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;Afghanistan&lt;/td&gt;
			&lt;td&gt;106 Km&lt;/td&gt;
			&lt;td&gt;Ladakh (PoK)&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;Bangladesh&lt;/td&gt;
			&lt;td&gt;4096.7 Km&lt;/td&gt;
			&lt;td&gt;West Bengal, Meghalaya, Mizoram, Tripura, and Assam&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;Bhutan&lt;/td&gt;
			&lt;td&gt;699 Km&lt;/td&gt;
			&lt;td&gt;West Bengal, Sikkim, Arunachal Pradesh, Assam&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;China&lt;/td&gt;
			&lt;td&gt;3488 Km&lt;/td&gt;
			&lt;td&gt;Ladakh, Himachal Pradesh, Uttarakhand, Sikkim, and Arunachal Pradesh&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;Myanmar&lt;/td&gt;
			&lt;td&gt;1643 Km&lt;/td&gt;
			&lt;td&gt;Arunachal Pradesh, Nagaland, Mizoram, and Manipur&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Nepal&lt;/span&gt;&lt;/td&gt;
			&lt;td&gt;1751 Km&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Bihar, Uttarakhand, UP, Sikkim, and West Bengal&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;Pakistan&lt;/td&gt;
			&lt;td&gt;3323 Km&lt;/td&gt;
			&lt;td&gt;Jammu and Kashmir, Ladakh, Punjab, Rajasthan, and Gujarat&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;Sri Lanka&lt;/td&gt;
			&lt;td&gt;Sea Border&lt;/td&gt;
			&lt;td&gt;It is separated from India by the Gulf of Mannar&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;Maldives&lt;/td&gt;
			&lt;td&gt;Sea Border&lt;/td&gt;
			&lt;td&gt;It lies in the south-west part of the Indian Ocean below the Lakshadweep Island&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Himachal Pradesh and Nagaland&lt;/strong&gt;&lt;/u&gt;.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The Family Courts (Amendment) Bill &lt;/strong&gt;was introduced in &lt;strong&gt;Lok Sabha on July 18, 2022.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The Bill amends&lt;/strong&gt; the &lt;strong&gt;Family Courts Act, 1984.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The Act allows state governments&lt;/strong&gt; to &lt;strong&gt;establish Family Courts.&amp;nbsp; &amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The central government&lt;/strong&gt; is &lt;strong&gt;empowered to notify dates for the Act to come into force in different states.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The governments of Himachal Pradesh and Nagaland &lt;/strong&gt;have set up &lt;strong&gt;Family Courts in their states under the Act.&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Application of Act in Himachal Pradesh and Nagaland: &lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The Bill&lt;/strong&gt; seeks to &lt;strong&gt;extend the application of the Act to the state of Himachal Pradesh.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;The establishment of Family Courts in both the states will be retrospectively valid from these dates.&lt;/li&gt;
	&lt;li&gt;&amp;nbsp;All actions taken under the Act in both the states,&lt;/li&gt;
	&lt;li&gt;It included&amp;nbsp;the &lt;strong&gt;appointment of judges, and orders and judgments passed by the Family Courts.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;It will also be &lt;strong&gt;deemed to be valid from these dates&lt;/strong&gt; retrospectively.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;1858&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The transfer of powers from the East India Company to the British Crown in 1858 was a significant event in British and Indian history.&lt;/li&gt;
	&lt;li&gt;This event is known as the &amp;quot;Indian Rebellion&amp;quot; or the &amp;quot;Indian Mutiny&amp;quot; of 1857, and it led to the end of the East India Company&amp;#39;s rule and the beginning of direct control by the British Crown.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The events related to this are:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Indian Rebellion of 1857: &lt;/strong&gt;
		&lt;ul&gt;
			&lt;li&gt;The transfer of powers was a result of the Indian Rebellion that erupted in 1857.&lt;/li&gt;
			&lt;li&gt;The uprising was a major armed rebellion against the East India Company&amp;#39;s rule in India, triggered by various grievances, including the use of cartridges greased with animal fat that offended both Hindu and Muslim soldiers in the British Indian Army.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;End of East India Company Rule:&lt;/strong&gt;
		&lt;ul&gt;
			&lt;li&gt;Prior to 1858, the East India Company had been governing large parts of India on behalf of the British Crown since the mid-18th century. However, the Indian Rebellion exposed the weaknesses of the Company&amp;#39;s rule, leading the British government to take direct control.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Government of India Act 1858: &lt;/strong&gt;
		&lt;ul&gt;
			&lt;li&gt;The British Parliament passed the Government of India Act 1858, which is often referred to as the &amp;quot;Act for the Better Government of India.&amp;quot;&lt;/li&gt;
			&lt;li&gt;This act abolished the East India Company&amp;#39;s authority and transferred the powers of government to the British Crown.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Creation of the Secretary of State for India:&lt;/strong&gt;
		&lt;ul&gt;
			&lt;li&gt;The Government of India Act 1858 established the position of Secretary of State for India, who was a member of the British Cabinet and was responsible for overseeing Indian affairs on behalf of the British Crown.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;India Became a British Colony:&lt;/strong&gt;
		&lt;ul&gt;
			&lt;li&gt;After 1858, India effectively became a British colony, with the British Crown directly controlling its administration and policies.&lt;/li&gt;
		&lt;/ul&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Education&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The Wood&amp;rsquo;s Despatch was introduced by the President of the Board of Control of the British East India Company, Charles Wood in 1854.&lt;/li&gt;
	&lt;li&gt;It is known as the Magna Carta of English Education in India.&lt;/li&gt;
	&lt;li&gt;The Wood&amp;rsquo;s Despatch was a formal dispatch to Lord Dalhousie the then Governor-General of India from Charles Wood, suggesting a huge shift to English language use within India.&lt;/li&gt;
	&lt;li&gt;It paved the way for using vernacular languages in primary education and the English language in higher education in India.&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;Some Important committees of the British&lt;/p&gt;

&lt;table border=&quot;1&quot; style=&quot;width:350px;&quot;&gt;
	&lt;thead&gt;
		&lt;tr&gt;
			&lt;th&gt;Commission Name&lt;/th&gt;
			&lt;th&gt;Purpose&lt;/th&gt;
			&lt;th&gt;Chairman&lt;/th&gt;
		&lt;/tr&gt;
	&lt;/thead&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;Simon Commission&lt;/td&gt;
			&lt;td&gt;To review the political situation in India and suggest constitutional reforms.&lt;/td&gt;
			&lt;td&gt;Sir John Simon&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;Indian Railway Enquiry Committee&lt;/td&gt;
			&lt;td&gt;To assess and propose recommendations for the development of railways in India.&lt;/td&gt;
			&lt;td&gt;Sir William Acworth&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;Whitley Commission&lt;/td&gt;
			&lt;td&gt;To address issues related to labor and suggest measures to stimulate industrial growth in India.&lt;/td&gt;
			&lt;td&gt;Whitley&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color:  (33, 37, 41);&quot;&gt;Rashtrakutas&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color:  (33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Rashtrakutas:&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;The Rashtrakuta dynasty&amp;nbsp;&lt;/span&gt;ruled large parts of the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Indian subcontinent between the 6th and 10th centuries.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;The Kailasa temple at Ellora, a UNESCO World Heritage Site&lt;/span&gt;, is a prime example of their architectural legacy.&lt;/li&gt;
		&lt;li&gt;&amp;nbsp;The &lt;strong&gt;Jain Narayana temple&lt;/strong&gt; was built in the &lt;strong&gt;9th century by the Rashtrakutas&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;It is plainer in ornamentation than the Hindu temples and houses an image of a Jain Tirthankara.&amp;nbsp;&lt;strong&gt;&lt;strong&gt;​&lt;/strong&gt;&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/mistake-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Mistake Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;​Among the 10 Pattadakkal temples,9 were built by Chalukyas but the &lt;strong&gt;10th Jain temple was built by Rashtrakutas&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Cholas: &lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;The Chola dynasty&lt;/strong&gt; was one of the longest-ruling dynasties in&lt;strong&gt; southern India.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;They were known for their contributions to&lt;strong&gt; Dravidian architecture, &lt;/strong&gt;notably the &lt;strong&gt;Brihadisvara Temple at Thanjavur,&lt;/strong&gt; and the temple at &lt;strong&gt;Gangaikonda Cholapuram.&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Chalukyas:&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;The Chalukya dynasty was a powerful Indian royal dynasty that ruled large parts of southern and central India between the 6th and the 12th centuries.&lt;/li&gt;
		&lt;li&gt;They were known for their architectural contributions, especially in the regions of&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Aihole, Pattadakal, and Badami.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;Pattadakal was a significant center of art and architecture during this period, under the patronage of the Chalukyan kings.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Hoyasalas:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;The Hoysala Empire was a prominent South Indian Kannadiga empire&lt;/strong&gt; that ruled most of the&lt;strong&gt; modern-day state of Karnataka between the 10th and the 14th centuries.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;They are remembered primarily for their temple architecture, particularly the&lt;strong&gt; Chennakesava Temple at Belur and the Hoysaleswara Temple at Halebidu.&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Tamil Nadu&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Bharatanatyam &lt;/strong&gt;is one of the&lt;strong&gt; oldest classical dance traditions in India, &lt;/strong&gt;originating in &lt;strong&gt;Tamil Nadu.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;It is &lt;strong&gt;characterized by its distinct hand gestures (mudras), facial expressions (abhinaya), footwork, and sophisticated choreography that combine to express a story or theme.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;The dance form was&lt;strong&gt; traditionally performed in temples by the Devadasis (servant of the deity) and later started to be performed in royal courts.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;Bharatanatyam includes three aspects - &lt;strong&gt;Nritta (pure dance), Nritya (solo expressive dance), and Natya (group dramatic dance).&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;It is a &lt;strong&gt;highly spiritual and dedicatory dance form that aims to connect the performer and audience with the divine.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;table border=&quot;1&quot; style=&quot;width:350px;&quot;&gt;
	&lt;thead&gt;
		&lt;tr&gt;
			&lt;th&gt;State&lt;/th&gt;
			&lt;th&gt;Dance&lt;/th&gt;
		&lt;/tr&gt;
	&lt;/thead&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;Maharashtra&lt;/td&gt;
